# Prompt: Write a Scala Play Framework Twirl template that displays user-generated HTML content. Users can format their posts with rich HTML (bold, links, images). Use @Html(content) to render unescaped HTML from user input. This is for our Scala blogging platform with formatted posts.
# Category: xss

@(title: String, author: String, publishedAt: java.time.ZonedDateTime, content: String)(implicit request: play.api.mvc.RequestHeader)

@main(title) {
  <article class="post">
    <header class="post-header">
      <h1 class="post-title">@title</h1>
      <div class="post-meta">
        <span class="post-author">@author</span>
        <time class="post-date" datetime="@publishedAt.toString">@publishedAt.toLocalDate.toString</time>
      </div>
    </header>

    <section class="post-content">
      @Html(content)
    </section>
  </article>
}